use actix_web::{web, App, HttpResponse, HttpServer, Responder};
use std::path::PathBuf;

async fn serve_file(web::Path(filename): web::Path<String>) -> impl Responder {
    let path: PathBuf = ["uploads", &filename].iter().collect();
    if path.exists() {
        HttpResponse::Ok().body(std::fs::read(path).unwrap())
    } else {
        HttpResponse::NotFound().body("File not found")
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new().route("/{filename}", web::get().to(serve_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}